INSERT INTO juegos (id_juego, nombre, descripcion, editorial, jugadores) VALUES 
(12,'Aventureros al tren Europa','Juego de estrategia donde los jugadores construyen rutas ferroviarias por Europa. Combina planificación, bloqueo y gestión de cartas. Ideal para jugadores casuales y experimentados.','Maldon','2-5'),
(13,'Dungeons & Drinks','Juego party donde sos un heroe pasado de copas, que entra junto con sus amigos a un dungeon lleno de peligros y monstruos que no molestan a nadie. Se compite por ver quien es el mejor tomando y matando bichos','Bureau de Juegos','3-8'),
(14,'Virus','Juego de cartas ágil donde tenés que completar un cuerpo sano mientras saboteás a los demás. Ataques, curas y caos constante. Fácil de aprender y muy competitivo.','El Dragon Azul','2-8'),
(15,'Azul','Juego abstracto de estrategia donde decorás mosaicos portugueses. Puntúa bien quien planifica y castiga errores. Elegante, simple y profundo.','Maldon','2-4'),
(16,'Say My Name','Juego party de deducción y asociación de palabras. Ideal para grupos grandes y risas rápidas. La creatividad es clave para ganar.','Bureau de Juegos','4-16'),
(17,'Coup','Juego de engaño donde mentir es parte de la estrategia. Eliminación rápida y mucha tensión en cada turno.','El Dragon Azul','3-10'),
(18,'El Camarero','El Camarero es un juego de mesa que hace honor a la memoria prodigiosa de los camareros de todo el mundo. ¿Creés que podrías ser un gran camarero? Entradas, principales, guarniciones, postres y bebidas. Debés recordar todos los pedidos de la mesa y servir los platos que salen de la cocina. ¡Pero estate atento! Si alguien comete algún error, podés salvar el honor de la profesión corrigiendo al distraído.','Maldon','2-10'),
(19,'Skull King','Juego de bazas con piratas, apuestas y sorpresas. Ganar no siempre significa llevarse todas las manos. Mucha emoción y riesgo en cada ronda.','Devir','3-8'),
(20,'Catan','Clásico juego de estrategia y comercio. Construí rutas, ciudades y negociá recursos con otros jugadores. Cada partida es distinta.','Devir','2-4'),
(21,'King of Tokyo','Juego de dados y combates con monstruos gigantes. Riesgo, ataques y decisiones rápidas. Muy divertido y visual.','Bureau de Juegos','2-6'),
(22,'Sushi Go Party','Juego de cartas de draft donde armás combinaciones de sushi. Simple, colorido y rápido. Ideal para todas las edades.','Devir','2-8'),
(23,'La Resistencia','Juego social de roles ocultos y deducción. Los jugadores deben descubrir a los traidores del grupo. Ideal para generar discusiones intensas.','Devir','4-10'),
(24,'Las Vegas Baby','Un juego de preguntas y respuestas en el que podés ganar sabiendo mucho… o apostando con astucia! En Las Vegas, Baby! no hace falta que sepas las respuestas exactas, sólo trata de acertar lo más que puedas y luego apuesta incluso contra ti mismo para ganar!','Neptuno','3-7'),
(25,'Tapple','Juego de palabras contra reloj. Pensá rápido antes de que se acaben las letras. Ideal para grupos grandes.','Importado','2-10'),
(26,'Pequeños Grandes Mechs','Juego de estrategia compacta con robots gigantes. Mucha profundidad en una caja pequeña. Control de área y combate táctico.','Devir','2-4'),
(27,'Taco Gato Cabra Queso Pizza','Juego de reflejos y repetición absurda. Perdedor se lleva cartas y castigos. Risas aseguradas.','Bureau de Juegos','3-10'),
(28,'Whitehall','Juego de deducción asimétrica inspirado en Jack el Destripador. Un jugador se esconde y los demás investigan. Tenso y estratégico','Casero','4'),
(29,'Dungeons & Dragons','Juego de rol narrativo donde la imaginación manda. Aventuras épicas, personajes únicos y decisiones abiertas. No hay dos partidas iguales.','Casero','3-8'),
(30,'Cada Cosa en su Lugar','¡Ubicá cada cosa en su lugar y descubrì la o las reglas secretas!','Maldon','3-8'),
(31,'Dobble','Juego de observación extrema. Siempre hay un símbolo en común entre dos cartas. Rápido, simple y adictivo.','Top Toys','2-8'),
(32,'Sospechosos Inusuales','Un juego cooperativo que va a poner a prueba tu intuición... pero también tus prejuicios.','Bureau de Juegos','3-10'),
(33,'Código Secreto Imágenes','Juego de asociación visual por equipos. Las pistas deben ser precisas para evitar errores. Ideal para grupos','Devir','4-10'),
(34,'Bang','Juego de roles ocultos ambientado en el Lejano Oeste. Disparos, traiciones y alianzas. Muy interactivo.','Top Toys','3-8'),
(35,'Sandwich Wars','El cocinero que prepare los mejores sándwiches (y aproveche mejor las oportunidades que se presenten) será aclamado como el ganador y gran maestro sandwichero!','Otros','3-6'),
(36,'Actuá Rápido','Juego party de actuación y velocidad mental. Mucho humor garantizado.Digalo con mimica','Bureau de Juegos','2-10'),
(37,'Descifrá el Código','Juego de mesa de deducción rápida (15-20 min)  donde el objetivo es adivinar un código oculto de números blancos y negros (0-9, el 5 es verde) antes que los rivales','Bureau de Juegos','2-4'),
(38,'Extinción','Es un juego de mesa de cartas rápido donde los participantes actúan como equipos de rescate en un mundo perdido. El objetivo es salvar dinosaurios de la erupción volcánica, llevándolos a zonas seguras antes de que el contador de extinción llegue a cinco. ','Top Toys','2-6'),
(39,'Póker de Bichos','Se comparten bichos ofreciendo una carta boca abajo a otro jugador y diciendo, al mismo tiempo, qué bicho aparece dibujado; ¡pero se puede decir la verdad o una mentira!','Devir','3-8'),
(40,'Unanimo Party','Juego de pensar como la mayoría. Cuanto más coincidan las respuestas, mejor. Ideal para grupos grandes.','Maldon','3-10'),
(41,'Munchkin','Juego de cartas de humor y traición en mazmorras. Subí de nivel traicionando a tus amigos. Caótico y muy divertido.','Bureau de Juegos','3-8'),
(42,'Pistas Cruzadas','Es un juego de mesa cooperativo, rápido y creativo, diseñado para conectar conceptos mediante una sola pista. Los jugadores deben colaborar para adivinar pares de palabras ocultas en una grilla, utilizando una única palabra como pista, buscando la mayor puntuación ','Bureau de Juegos','3-10'),
(43,'El Erudito','Juego de preguntas y conocimiento general con apuestas, donde las tarjetas se diferencian en la forma en que son planteadas las preguntas o consignas. Estrategia ligera con enfoque cultural. Ideal para amantes de los trivias.','Maldon','3-10'),
(44,'El Ilustrado','El Ilustrado es un juego de mesa de cultura general con tarjetas ilustradas donde hay que reconocer, ubicar, identificar, ordenar o clasificar diferentes elementos para demostrar todo lo que sabés. ','Maldon','3-10'),
(45,'Tomalo Vos','Un juego para previas, en el que tu objetivo es lograr que tus amigos/as tomen mas que vos. ','Bureau de Juegos','3-10'),
(46,'El Memorioso','El Memorioso es un juego de mesa en donde la memoria y la agilidad mental son claves para ganar. Al sacar una tarjeta, corre el tiempo y se compite pare ver quién recuerda más (y los más atípicos) elementos de una determinada lista. Con una cuota de estrategia se podrán duplicar o dividir los puntos de los jugadores, según sus conocimientos en las más variadas temáticas existen','Maldon','3-10'),
(47,'Exploding Kittens','Juego de cartas rápido y absurdo. Evitá explotar usando tácticas y sabotajes. Muy popular y fácil de aprender.','Top Toys','2-4'),
(48,'HDP','Juego party irreverente y humor negro. Pensado para adultos. Provoca risas y polémica.','Bureau de Juegos','3-10'),
(49,'Supercats','Los participantes transforman 5 gatitos en supergatos mostrando dedos simultáneamente. Tras lograrlo, ese jugador se enfrenta al RoboDog','Bureau de Juegos','3-6'),
(50,'Pica Pica','Juego centrado en la gestión de mano y la acumulación de puntos mínimos. El objetivo es evitar sumar cartas picantes, logrando llevarse conjuntos de cartas (colores o números) del centro de la mesa mediante cartas especiales. ','Otros','3-6'),
(51,'Red 7','Es un juego de cartas rápido y dinámico donde el objetivo es no quedar eliminado cumpliendo la regla de victoria actual al final de cada turno. Con cartas numeradas del 1 al 7 en siete colores, las reglas cambian constantemente, exigiendo astucia para ganar con la carta más alta o ajustando las condiciones del juego. ','Casero','3-6'),
(52,'The Mind','Se deben colocar cartas numeradas del 1 al 100 en orden ascendente en el centro de la mesa. El reto principal es que no se puede hablar, intercambiar información ni hacer señas, basándose únicamente en la intuición y la conexión silenciosa para sincronizar sus mentes. ','Casero','2-10'),
(53,'Aventureros y el Medallón de Ra','El objetivo es obtener y conservar la carta del Medallón de Ra al finalizar el mazo, usando estrategia para robar, defenderse y engañar a los rivales. ','Neptuno','3-6'),
(54,'Uga Buga','El objetivo es convertirse en el líder de la tribu repitiendo secuencias de sonidos y gestos cavernícolas sin equivocarse. Los jugadores juegan cartas, añaden acciones salvajes, y si fallan, se llevan el mazo acumulado. ','Bureau de Juegos','3-8'),
(55,'Caca','El objetivo es no rebalsar el inodoro. Los jugadores tiran cartas de \"caca\" intentando no superar la capacidad numérica del inodoro; si lo hacen, \"tapan\" el baño y se llevan las cartas. ','Bureau de Juegos','2-6'),
(56,'Líderes de Euphoria','Es un juego de deducción social con mucho engaño e interacción. Se juega en equipos aunque también permite que gane un solo jugador, lo cual hace que desconfíes hasta de tus propios compañeros.','Bureau de Juegos','3-8'),
(57,'Mal Trago','Cada participante actúa como un goblin probando pociones para una bruja. El objetivo es ser el último superviviente, evitando pociones mortales y utilizando antídotos y cartas de acción para sobrevivir o convertir a otros en fantasmas','Top Toys','4-10'),
(58,'Dungeon Lite','Es un juego de mesa cooperativo de tipo dungeon crawler. En partidas de unos 90 minutos, los héroes exploran mazmorras generadas aleatoriamente, mejoran equipo y luchan contra orcos y un dragón final, destacando por su rápida preparación, reglas sencillas y alta intensidad. ','Bureau de Juegos','2-4'),
(59,'La Tripulación','Los jugadores actúan como astronautas, colaborando en silencio para superar 50 misiones con dificultad creciente, donde la comunicación está limitada y se deben cumplir tareas específicas para ganar. ','Devir','2-5'),
(60,'Adigma','Los participantes resuelven simultáneamente acertijos, acertijos visuales y lógicos de 29 categorías distintas para ganar monedas y avanzar por un tablero de casillas sorpresa','Otros','3-10'),
(61,'Flip 7','Juego de cartas de riesgo y push your luck. Saber cuándo parar es crucial. Muy ágil y adictivo.','Importados','3-10'),
(62,'Dungeon Mayhem','Los jugadores eligen mazos únicos para atacar, defenderse y curarse, con el objetivo de ser el último aventurero en pie. ','Importados','2-6');
