-- SCRIPT DE IMPORTACIÓN DE DATOS (MySQL -> PostgreSQL)

-- 1. Insertar Usuarios

-- 2. Insertar Juegos

-- 3. Insertar Imágenes

-- 4. Insertar Puntuaciones

-- 5. Sincronizar secuencias (para que los próximos inserts automáticos no fallen)
SELECT setval('usuarios_id_usuario_seq', (SELECT MAX(id_usuario) FROM usuarios));
SELECT setval('juegos_id_juego_seq', (SELECT MAX(id_juego) FROM juegos));
SELECT setval('imagenes_juegos_id_imagen_seq', (SELECT MAX(id_imagen) FROM imagenes_juegos));
SELECT setval('puntuaciones_id_puntuacion_seq', (SELECT MAX(id_puntuacion) FROM puntuaciones));
